module imem (      input logic i_clk,      input  logic [31:0]  i_addr,  	     output logic [31:0]  o_rdata  );  logic [10:0] word_addr;		  logic [31:0] memory_word [2047:0];		    assign word_addr = i_addr[12:2];		   initial begin         $readmemh("isa_4b.hex", memory_word);    end													 always_ff @(posedge i_clk) begin    o_rdata <= memory_word[word_addr];endendmodule